void send_binary(int value) {
    char buffer[8];
    sprintf(buffer, "%d\r\n", value);          // Convert 0 or 1 to string
    CDC_Transmit_FS((uint8_t*)buffer, strlen(buffer)); // Send over USB
    audio_requested = 1;

}



