  MX_I2S3_Init();
  MX_SPI1_Init();
  MX_CRC_Init();
  MX_I2S2_Init();
  MX_PDM2PCM_Init();
  MX_USB_DEVICE_Init();
  /* USER CODE BEGIN 2 */

  HAL_GPIO_WritePin(GPIOD, GPIO_PIN_4, GPIO_PIN_RESET);
      HAL_Delay(10);


