void Process_PDM_Block(uint8_t* pIn)
{

    PDM_Filter(pIn, PCM_Mono, &PDM1_filter_handler); // PCM_Mono filled with PCM_OUT_SIZE int16 samples

    if(audio_requested)
    {
    	memcpy(PCM_Mono_Copy,PCM_Mono,2048*sizeof(uint16_t));

    	audio_requested = 0;
    	audio_ready = 1;
    }


}


void HAL_I2S_RxHalfCpltCallback(I2S_HandleTypeDef *hi2s)
{
	//Process_PDM_Block(&PDM_Buffer[0], &I2S3_TxBuffer[0]);
	Process_PDM_Block(&PDM_Buffer[0]);
}

void HAL_I2S_RxCpltCallback(I2S_HandleTypeDef *hi2s)
{
	//Process_PDM_Block(&PDM_Buffer[PDM_IN_SIZE], &I2S3_TxBuffer[PCM_OUT_SIZE]);
	Process_PDM_Block(&PDM_Buffer[PDM_IN_SIZE]);

}


